bad_example:
try {
    connect(host, port);
} catch (IOException e) {
    throw new RuntimeException(e); // no context
}

CODE_EXAMPLE:
try {
    connect(host, port);
} catch (IOException e) {
    throw new ConnectionException(
            String.format("Failed to connect to %s:%d", host, port), e);
}

UNIT_TEST_EXAMPLE:
@Test
public void connect_throwsConnectionException_withHostAndPort() {
    NetworkClient client = new NetworkClient();
    ConnectionException ex = assertThrows(ConnectionException.class,
            () -> client.connect("unreachable", 9999));
    assertTrue(ex.getMessage().contains("unreachable"));
    assertTrue(ex.getMessage().contains("9999"));
    assertNotNull(ex.getCause());
}
